INSERT INTO `background_bonds` VALUES (1,1,'I would die to recover an ancient relic of my faith that was lost long ago.'),(2,1,'I will someday get revenge on the corrupt temple hierarchy who branded me a heretic.'),(3,1,'I owe my life to the priest who took me in when my parents died.'),(4,1,'Everything I do is for the common people.'),(5,1,'I will do anything to protect the temple where I served.'),(6,1,'I seek to preserve a sacred text that my enemies consider heretical and seek to destroy.'),(7,2,'I fleeced the wrong person and must work to ensure that this individual never crosses paths with me or those I care about.'),(8,2,'I owe everything to my mentor — a horrible person who\'s probably rotting in jail somewhere.'),(9,2,'Somewhere out there, I have a child who doesn\'t know me. I\'m making the world better for him or her.'),(10,2,'I come from a noble family, and one day I\'ll reclaim my lands and title from those who stole them from me.'),(11,2,'A powerful person killed someone I love. Some day soon, I\'ll have my revenge.'),(12,2,'I swindled and ruined a person who didn\'t deserve it. I seek to atone for my misdeeds but might never be able to forgive myself.'),(13,3,'I\'m trying to pay off an old debt I owe to a generous benefactor.'),(14,3,'My ill-gotten gains go to support my family.'),(15,3,'Something important was taken from me, and I aim to steal it back.'),(16,3,'I will become the greatest thief that ever lived.'),(17,3,'I\'m guilty of a terrible crime. I hope I can redeem myself for it.'),(18,3,'Someone I loved died because of a mistake I made. That will never happen again.'),(19,4,'My instrument is my most treasured possession, and it reminds me of someone I love.'),(20,4,'Someone stole my precious instrument, and someday I\'ll get it back.'),(21,4,'I want to be famous, whatever it takes.'),(22,4,'I idolize a hero of the old tales and measure my deeds against that person\'s.'),(23,4,'I will do anything to prove myself superior to my hated rival.'),(24,4,'I would do anything for the other members of my old troupe.'),(25,5,'I have a family, but I have no idea where they are. One day, I hope to see them again.'),(26,5,'I worked the land, I love the land, and I will protect the land.'),(27,5,'A proud noble once gave me a horrible beating, and I will take my revenge on any bully I encounter.'),(28,5,'My tools are symbols of my past life, and I carry them so that I will never forget my roots.'),(29,5,'I protect those who cannot protect themselves.'),(30,5,'I wish my childhood sweetheart had come with me to pursue my destiny.'),(31,6,'The workshop where I learned my trade is the most important place in the world to me.'),(32,6,'I created a great work for someone, and then found them unworthy to receive it. I\'m still looking for someone worthy.'),(33,6,'I owe my guild a great debt for forging me into the person I am today.'),(34,6,'I pursue wealth to secure someone\'s love.'),(35,6,'One day I will return to my guild and prove that I am the greatest artisan of them all.'),(36,6,'I will get revenge on the evil forces that destroyed my place of business and ruined my livelihood.'),(37,7,'Nothing is more important than the other members of my hermitage, order, or association.'),(38,7,'I entered seclusion to hide from the ones who might still be hunting me. I must someday confront them.'),(39,7,'I\'m still seeking the enlightenment I pursued in my seclusion, and it still eludes me.'),(40,7,'I entered seclusion because I loved someone I could not have.'),(41,7,'Should my discovery come to light, it could bring ruin to the world.'),(42,7,'My isolation gave me great insight into a great evil that only I can destroy.'),(43,8,'I will face any challenge to win the approval of my family.'),(44,8,'My house\'s alliance with another noble family must be sustained at all costs.'),(45,8,'Nothing is more important than the other members of my family.'),(46,8,'I am in love with the heir of a family that my family despises.'),(47,8,'My loyalty to my sovereign is unwavering.'),(48,8,'The common folk must see me as a hero of the people.'),(49,9,'My family, clan, or tribe is the most important thing in my life, even when they are far from me.'),(50,9,'An injury to the unspoiled wilderness of my home is an injury to me.'),(51,9,'I will bring terrible wrath down on the evildoers who destroyed my homeland.'),(52,9,'I am the last of my tribe, and it is up to me to ensure their names enter legend.'),(53,9,'I suffer awful visions of a coming disaster and will do anything to prevent it.'),(54,9,'It is my duty to provide children to sustain my tribe.'),(55,10,'It is my duty to protect my students.'),(56,10,'I have an ancient text that holds terrible secrets that must not fall into the wrong hands.'),(57,10,'I work to preserve a library, university, scriptorium, or monastery.'),(58,10,'My life\'s work is a series of tomes related to a specific field of lore.'),(59,10,'I\'ve been searching my whole life for the answer to a certain question.'),(60,10,'I sold my soul for knowledge. I hope to do great deeds and win it back.'),(61,11,'I\'m loyal to my captain first, everything else second.'),(62,11,'The ship is most important — crewmates and captains come and go.'),(63,11,'I\'ll always remember my first ship.'),(64,11,'In a harbor town, I have a paramour whose eyes nearly stole me from the sea.'),(65,11,'I was cheated out of my fair share of the profits, and I want to get my due.'),(66,11,'Ruthless pirates murdered my captain and crewmates, plundered our ship, and left me to die. Vengeance will be mine.'),(67,12,'I would still lay down my life for the people I served with.'),(68,12,'Someone saved my life on the battlefield. To this day, I will never leave a friend behind.'),(69,12,'My honor is my life.'),(70,12,'I\'ll never forget the crushing defeat my company suffered or the enemies who dealt it.'),(71,12,'Those who fight beside me are those worth dying for.'),(72,12,'I fight for those who cannot fight for themselves.'),(73,13,'My town or city is my home, and I\'ll fight to defend it.'),(74,13,'I sponsor an orphanage to keep others from enduring what I was forced to endure.'),(75,13,'I owe my survival to another urchin who taught me to live on the streets.'),(76,13,'I owe a debt I can never repay to the person who took pity on me.'),(77,13,'I escaped my life of poverty by robbing an important person, and I\'m wanted for it.'),(78,13,'No one else should have to suffer the way I did.');
