INSERT INTO `background_flaws` VALUES (1,1,'I judge others harshly, and myself even more severely.'),(2,1,'I put too much trust in those who wield power within my temple\'s hierarchy.'),(3,1,'My piety sometimes leads me to blindly trust those that profess faith in my god.'),(4,1,'I am inflexible in my thinking.'),(5,1,'I am suspicious of strangers and expect the worst of them.'),(6,1,'Once I pick a goal, I become obsessed with it to the detriment of everything else in my life.'),(7,2,'I can\'t resist a pretty face.'),(8,2,'I\'m always in debt. I spend my ill-gotten gains on decadent luxuries faster than I bring them in.'),(9,2,'I\'m convinced that no one could ever fool me the way I fool others.'),(10,2,'I\'m too greedy for my own good. I can\'t resist taking a risk if there\'s money involved.'),(11,2,'I can\'t resist swindling people who are more powerful than me.'),(12,2,'I hate to admit it and will hate myself for it, but I\'ll run and preserve my own hide if the going gets tough.'),(13,3,'When I see something valuable, I can\'t think about anything but how to steal it.'),(14,3,'When faced with a choice between money and my friends, I usually choose the money.'),(15,3,'If there\'s a plan, I\'ll forget it. If I don\'t forget it, I\'ll ignore it.'),(16,3,'I have a \"tell\" that reveals when I\'m lying.'),(17,3,'I turn tail and run when things look bad.'),(18,3,'An innocent person is in prison for a crime that I committed. I\'m okay with that.'),(19,4,'I\'ll do anything to win fame and renown.'),(20,4,'I\'m a sucker for a pretty face.'),(21,4,'A scandal prevents me from ever going home again. That kind of trouble seems to follow me around.'),(22,4,'I once satirized a noble who still wants my head. It was a mistake that I will likely repeat.'),(23,4,'I have trouble keeping my true feelings hidden. My sharp tongue lands me in trouble.'),(24,4,'Despite my best efforts, I am unreliable to my friends.'),(25,5,'The tyrant who rules my land will stop at nothing to see me killed.'),(26,5,'I\'m convinced of the significance of my destiny, and blind to my own limitations and the risk of failure.'),(27,5,'The people who knew me when I was young know my shameful secret, so I can never go home again.'),(28,5,'I have a weakness for the vices of the city, especially hard drink.'),(29,5,'Secretly, I believe that things would be better if I were a tyrant lording over the land.'),(30,5,'I have trouble trusting in my allies.'),(31,6,'I\'ll do anything to get my hands on something rare or priceless.'),(32,6,'I\'m quick to assume that someone is trying to cheat me.'),(33,6,'No one must ever learn that I once stole money from guild coffers.'),(34,6,'I\'m never satisfied with what I have — I always want more.'),(35,6,'I would kill to acquire a signature piece from a famous artist.'),(36,6,'I\'m horribly jealous of anyone who can outshine my handiwork.'),(37,7,'Now that I\'ve returned to the world, I enjoy its delights a little too much.'),(38,7,'I harbor dark, bloodthirsty thoughts that my isolation and meditation failed to quell.'),(39,7,'I am dogmatic in my thoughts and philosophy.'),(40,7,'I let my need to win arguments overshadow friendships and harmony.'),(41,7,'I\'d risk too much to uncover a lost bit of knowledge.'),(42,7,'I like keeping secrets and won\'t share them with anyone.'),(43,8,'I secretly believe that everyone is beneath me.'),(44,8,'I hide a truly scandalous secret that could ruin my family forever.'),(45,8,'I too often hear veiled insults and threats in every word addressed to me, and I\'m quick to anger.'),(46,8,'I have an insatiable desire for carnal pleasures.'),(47,8,'In fact, the world does revolve around me.'),(48,8,'By my words and actions, I often bring shame to my family.'),(49,9,'I am too enamored of ale, wine, and other intoxicants.'),(50,9,'There\'s no room for caution in a life lived to the fullest.'),(51,9,'I remember every insult I\'ve received and nurse a silent resentment toward anyone who\'s ever wronged me.'),(52,9,'I am slow to trust members of other races, tribes, and societies.'),(53,9,'Violence is my answer to almost any challenge.'),(54,9,'Don\'t expect me to save those who can\'t save themselves. It is nature\'s way that the strong thrive and the weak perish.'),(55,10,'I am easily distracted by the promise of information.'),(56,10,'Most people scream and run when they see a demon. I stop and take notes on its anatomy.'),(57,10,'Unlocking an ancient mystery is worth the price of a civilization.'),(58,10,'I overlook obvious solutions in favor of complicated ones.'),(59,10,'I speak without really thinking through my words, invariably insulting others.'),(60,10,'I can\'t keep a secret to save my life, or anyone else\'s.'),(61,11,'I follow orders, even if I think they\'re wrong.'),(62,11,'I\'ll say anything to avoid having to do extra work.'),(63,11,'Once someone questions my courage, I never back down no matter how dangerous the situation.'),(64,11,'Once I start drinking, it\'s hard for me to stop.'),(65,11,'I can\'t help but pocket loose coins and other trinkets I come across.'),(66,11,'My pride will probably lead to my destruction.'),(67,12,'The monstrous enemy we faced in battle still leaves me quivering with fear.'),(68,12,'I have little respect for anyone who is not a proven warrior.'),(69,12,'I made a terrible mistake in battle that cost many lives, and I would do anything to keep that mistake secret.'),(70,12,'My hatred of my enemies is blinding and unreasoning.'),(71,12,'I obey the law, even if the law causes misery.'),(72,12,'I\'d rather eat my armor than admit when I\'m wrong.'),(73,13,'If I\'m outnumbered, I will run away from a fight.'),(74,13,'Gold seems like a lot of money to me, and I\'ll do just about anything for more of it.'),(75,13,'I will never fully trust anyone other than myself.'),(76,13,'I\'d rather kill someone in their sleep than fight fair.'),(77,13,'It\'s not stealing if I need it more than someone else.'),(78,13,'People who can\'t take care of themselves get what they deserve.');
/*!40000 ALTER TABLE `background_flaws` ENABLE KEYS */;
UNLOCK TABLES;

