INSERT INTO `background_ideals` VALUES (1,1,'Tradition. The ancient traditions of worship and sacrifice must be preserved and upheld.'),(2,1,'Charity. I always try to help those in need, no matter what the personal cost.'),(3,1,'Change. We must help bring about the changes the gods are constantly working in the world.'),(4,1,'Power. I hope to one day rise to the top of my faith\'s religious hierarchy.'),(5,1,'Faith. I trust that my deity will guide my actions. I have faith that if I work hard, things will go well.'),(6,1,'Aspiration. I seek to prove myself worthy of my god\'s favor by matching my actions against his or her teachings.'),(7,2,'Independence. I am a free spirit — no one tells me what to do.'),(8,2,'Fairness. I never target people who can\'t afford to lose a few coins.'),(9,2,'Creativity. I never run the same con twice.'),(10,2,'Friendship. Material goods come and go. Bonds of friendship last forever.'),(11,2,'Aspiration. I\'m determined to make something of myself.'),(12,2,'Redemption. I\'m trying to pay off an old debt I owe to a generous benefactor.'),(13,3,'Honor. I don\'t steal from others in the trade.'),(14,3,'Freedom. Chains are meant to be broken, as are those who would forge them.'),(15,3,'Charity. I steal from the wealthy so that I can help people in need.'),(16,3,'Greed. I will do whatever it takes to become wealthy.'),(17,3,'People. I\'m loyal to my friends, not to any ideals, and everyone else can take a trip down the Styx for all I care.'),(18,3,'Redemption. There\'s a spark of good in everyone.'),(19,4,'Beauty. When I perform, I make the world better than it was.'),(20,4,'Tradition. The stories, legends, and songs of the past must never be forgotten.'),(21,4,'Creativity. The world is in need of new ideas and bold action.'),(22,4,'Greed. I\'m only in it for the money and fame.'),(23,4,'People. I like seeing the smiles on people\'s faces when I perform.'),(24,4,'Honesty. Art should reflect the soul; it should come from within and reveal who we really are.'),(25,5,'Respect. People deserve to be treated with dignity and respect.'),(26,5,'Fairness. No one should get preferential treatment before the law, and no one is above the law.'),(27,5,'Freedom. Tyrants must not be allowed to oppress the people.'),(28,5,'Might. If I become strong, I can take what I want — what I deserve.'),(29,5,'Sincerity. There\'s no good in pretending to be something I\'m not.'),(30,5,'Destiny. Nothing and no one can steer me away from my higher calling.'),(31,6,'Community. It is the duty of all civilized people to strengthen the bonds of community and the security of civilization.'),(32,6,'Generosity. My talents were given to me so that I could use them to benefit the world.'),(33,6,'Freedom. Everyone should be free to pursue his or her own livelihood.'),(34,6,'Greed. I\'m only in it for the money.'),(35,6,'People. I\'m committed to the people I care about, not to ideals.'),(36,6,'Aspiration. I work hard to be the best there is at my craft.'),(37,7,'Greater Good. My gifts are meant to be shared with all, not used for my own benefit.'),(38,7,'Logic. Emotions must not cloud our sense of what is right and true.'),(39,7,'Free Thinking. Inquiry and curiosity are the pillars of progress.'),(40,7,'Power. Solitude and contemplation are paths toward mystical or magical power.'),(41,7,'Live and Let Live. Meddling in the affairs of others only causes trouble.'),(42,7,'Self-Knowledge. If you know yourself, there\'s nothing left to know.'),(43,8,'Respect. Respect is due to me because of my position, but all people regardless of station deserve to be treated with dignity.'),(44,8,'Responsibility. It is my duty to respect the authority of those above me, just as those below me must respect mine.'),(45,8,'Independence. I must prove that I can handle myself without the coddling of my family.'),(46,8,'Power. If I can attain more power, no one will tell me what to do.'),(47,8,'Family. Blood runs thicker than water.'),(48,8,'Noble Obligation. It is my duty to protect and care for the people beneath me.'),(49,9,'Change. Life is like the seasons, in constant change, and we must change with it.'),(50,9,'Greater Good. It is each person\'s responsibility to make the most happiness for the whole tribe.'),(51,9,'Honor. If I dishonor myself, I dishonor my whole clan.'),(52,9,'Might. The strongest are meant to rule.'),(53,9,'Nature. The natural world is more important than all the constructs of civilization.'),(54,9,'Glory. I must earn glory in battle, for myself and my clan.'),(55,10,'Knowledge. The path to power and self-improvement is through knowledge.'),(56,10,'Beauty. What is beautiful points us beyond itself toward what is true.'),(57,10,'Logic. Emotions must not cloud our logical thinking.'),(58,10,'No Limits. Nothing should fetter the infinite possibility inherent in all existence.'),(59,10,'Power. Knowledge is the path to power and domination.'),(60,10,'Self-Improvement. The goal of a life of study is the betterment of oneself.'),(61,11,'Respect. The thing that keeps a ship together is mutual respect between captain and crew.'),(62,11,'Fairness. We all do the work, so we all share in the rewards.'),(63,11,'Freedom. The sea is freedom — the freedom to go anywhere and do anything.'),(64,11,'Mastery. I\'m a predator, and the other ships on the sea are my prey.'),(65,11,'People. I\'m committed to my crewmates, not to ideals.'),(66,11,'Aspiration. Someday I\'ll own my own ship and chart my own destiny.'),(67,12,'Greater Good. Our lot is to lay down our lives in defense of others.'),(68,12,'Responsibility. I do what I must and obey just authority.'),(69,12,'Independence. When people follow orders blindly, they embrace a kind of tyranny.'),(70,12,'Might. In life as in war, the stronger force wins.'),(71,12,'Live and Let Live. Ideals aren\'t worth killing over or going to war for.'),(72,12,'Nation. My city, nation, or people are all that matter.'),(73,13,'Respect. All people, rich or poor, deserve respect.'),(74,13,'Community. We have to take care of each other, because no one else is going to do it.'),(75,13,'Change. The low are lifted up, and the high and mighty are brought down. Change is the nature of things.'),(76,13,'Retribution. The rich need to be shown what life and death are like in the gutters.'),(77,13,'People. I help the people who help me — that\'s what keeps us alive.'),(78,13,'Aspiration. I\'m going to prove that I\'m worthy of a better life.');
/*!40000 ALTER TABLE `background_ideals` ENABLE KEYS */;
