/*!40000 ALTER TABLE `background_personality_traits` DISABLE KEYS */;
INSERT INTO `background_personality_traits` VALUES (1,1,'I idolize a particular hero of my faith, and constantly refer to that person\'s deeds and example.'),(2,1,'I can find common ground between the fiercest enemies, empathizing with them and always working toward peace.'),(3,1,'I see omens in every event and action. The gods try to speak to us, we just need to listen.'),(4,1,'Nothing can shake my optimistic attitude.'),(5,1,'I quote (or misquote) sacred texts and proverbs in almost every situation.'),(6,1,'I am tolerant (or intolerant) of other faiths and respect (or condemn) the worship of other gods.'),(7,1,'I\'ve enjoyed fine food, drink, and high society among my temple\'s elite. Rough living grates on me.'),(8,1,'I\'ve spent so long in the temple that I have little practical experience dealing with people in the outside world.'),(9,2,'I fall in and out of love easily, and am always pursuing someone.'),(10,2,'I have a joke for every occasion, especially occasions where humor is inappropriate.'),(11,2,'Flattery is my preferred trick for getting what I want.'),(12,2,'I\'m a born gambler who can\'t resist taking a risk for a potential payoff.'),(13,2,'I lie about almost everything, even when there\'s no good reason to.'),(14,2,'Sarcasm and insults are my weapons of choice.'),(15,2,'I keep multiple holy symbols on me and invoke whatever deity seems most useful at any given moment.'),(16,2,'I pocket anything I see that might have some value.'),(17,3,'I always have a plan for what to do when things go wrong.'),(18,3,'I am always calm, no matter what the situation. I never raise my voice or let my emotions control me.'),(19,3,'The first thing I do in a new place is note the locations of everything valuable — or where such things could be hidden.'),(20,3,'I would rather make a new friend than a new enemy.'),(21,3,'I am incredibly slow to trust. Those who seem the fairest often have the most to hide.'),(22,3,'I don\'t pay attention to the risks in a situation. Never tell me the odds.'),(23,3,'The best way to get me to do something is to tell me I can\'t do it.'),(24,3,'I blow up at the slightest insult.'),(25,4,'I know a story relevant to almost every situation.'),(26,4,'Whenever I come to a new place, I collect local rumors and spread gossip.'),(27,4,'I\'m a hopeless romantic, always searching for that \"special someone.\"'),(28,4,'Nobody stays angry at me or around me for long, since I can defuse any amount of tension.'),(29,4,'I love a good insult, even one directed at me.'),(30,4,'I get bitter if I\'m not the center of attention.'),(31,4,'I\'ll settle for nothing less than perfection.'),(32,4,'I change my mood or my mind as quickly as I change key in a song.'),(33,5,'I judge people by their actions, not their words.'),(34,5,'If someone is in trouble, I\'m always ready to lend help.'),(35,5,'When I set my mind to something, I follow through no matter what gets in my way.'),(36,5,'I have a strong sense of fair play and always try to find the most equitable solution to arguments.'),(37,5,'I\'m confident in my own abilities and do what I can to instill that same confidence in others.'),(38,5,'Thinking is for other people. I prefer action.'),(39,5,'I misuse long words in an attempt to sound smarter.'),(40,5,'I get bored easily. When am I going to get on with my destiny?'),(41,6,'I believe that anything worth doing is worth doing right. I can\'t help it — I\'m a perfectionist.'),(42,6,'I\'m a snob who looks down on those who can\'t appreciate fine art.'),(43,6,'I always want to know how things work and what makes people tick.'),(44,6,'I\'m full of witty aphorisms and have a proverb for every occasion.'),(45,6,'I\'m rude to people who lack my commitment to hard work and fair play.'),(46,6,'I like to talk at length about my profession.'),(47,6,'I don\'t part with my money easily and will haggle tirelessly to get the best deal possible.'),(48,6,'I\'m well known for my work, and I want to make sure everyone appreciates it.'),(49,7,'I\'ve been isolated for so long that I rarely speak, preferring gestures and the occasional grunt.'),(50,7,'I am utterly serene, even in the face of disaster.'),(51,7,'The leader of my community had something wise to say on every topic, and I am eager to share that wisdom.'),(52,7,'I feel tremendous empathy for all who suffer.'),(53,7,'I\'m oblivious to etiquette and social expectations.'),(54,7,'I connect everything that happens to me to a grand, cosmic plan.'),(55,7,'I often get lost in my own thoughts and contemplation, becoming oblivious to my surroundings.'),(56,7,'I am working on a grand philosophical theory and love sharing my ideas.'),(57,8,'My eloquent flattery makes everyone I talk to feel like the most wonderful and important person in the world.'),(58,8,'The common folk love me for my kindness and generosity.'),(59,8,'No one could doubt by looking at my regal bearing that I am a cut above the unwashed masses.'),(60,8,'I take great pains to always look my best and follow the latest fashions.'),(61,8,'I don\'t like to get dirty, and I won\'t be caught dead in unsuitable accommodations.'),(62,8,'Despite my noble birth, I do not place myself above other folk. We all have the same blood.'),(63,8,'My favor, once lost, is lost forever.'),(64,8,'If you do me an injury, I will crush you, ruin your name, and salt your fields.'),(65,9,'I\'m driven by a wanderlust that led me away from home.'),(66,9,'I watch over my friends as if they were a litter of newborn pups.'),(67,9,'I once ran twenty-five miles without stopping to warn my clan of an approaching orc horde.'),(68,9,'I have a lesson for every situation, drawn from observing nature.'),(69,9,'I place no stock in wealthy or well-mannered folk. Money and manners won\'t save you from a hungry owlbear.'),(70,9,'I\'m always picking things up, absently fiddling with them, and sometimes accidentally breaking them.'),(71,9,'I feel far more comfortable around animals than people.'),(72,9,'I was, in fact, raised by wolves.'),(73,10,'I use polysyllabic words that convey the impression of great erudition.'),(74,10,'I\'ve read every book in the world\'s greatest libraries — or I like to boast that I have.'),(75,10,'I\'m used to helping out those who aren\'t as smart as I am, and I patiently explain anything and everything to others.'),(76,10,'There\'s nothing I like more than a good mystery.'),(77,10,'I\'m willing to listen to every side of an argument before I make my own judgment.'),(78,10,'I... speak... slowly... when talking to idiots, which almost everyone is compared to me.'),(79,10,'I am horribly, horribly awkward in social situations.'),(80,10,'I\'m convinced that people are always trying to steal my secrets.'),(81,11,'My friends know they can rely on me, no matter what.'),(82,11,'I work hard so that I can play hard when the work is done.'),(83,11,'I enjoy sailing into new ports and making new friends over a flagon of ale.'),(84,11,'I stretch the truth for the sake of a good story.'),(85,11,'To me, a tavern brawl is a nice way to get to know a new city.'),(86,11,'I never pass up a friendly wager.'),(87,11,'My language is as foul as an otyugh nest.'),(88,11,'I like a job well done, especially if I can convince someone else to do it.'),(89,12,'I\'m always polite and respectful.'),(90,12,'I\'m haunted by memories of war. I wake up screaming at the terrors of my past.'),(91,12,'I\'ve lost too many friends, and I\'m slow to make new ones.'),(92,12,'I\'m full of inspiring and cautionary tales from my military experience relevant to almost every combat situation.'),(93,12,'I can stare down a hell hound without flinching.'),(94,12,'I enjoy being strong and like breaking things.'),(95,12,'I have a crude sense of humor.'),(96,12,'I face problems head-on. A simple, direct solution is the best path to success.'),(97,13,'I hide scraps of food and trinkets away in my pockets.'),(98,13,'I ask a lot of questions.'),(99,13,'I like to squeeze into small places where no one else can get to me.'),(100,13,'I sleep with my back to a wall or tree, with everything I own wrapped in a bundle in my arms.'),(101,13,'I eat like a pig and have bad manners.'),(102,13,'I think anyone who\'s nice to me is hiding evil intent.'),(103,13,'I don\'t like to bathe.'),(104,13,'I bluntly say what other people are hinting at or dancing around.');
/*!40000 ALTER TABLE `background_personality_traits` ENABLE KEYS */;
UNLOCK TABLES;

