  `electrum_pieces` int NOT NULL DEFAULT '0',
  `gold_pieces` int NOT NULL DEFAULT '0',
  `platinum_pieces` int NOT NULL DEFAULT '0',
  `personality_traits` text COLLATE utf8mb4_unicode_ci,
  `ideals` text COLLATE utf8mb4_unicode_ci,
