  `natural_armor_bonus` int DEFAULT NULL,
  `initiative_bonus` int NOT NULL DEFAULT '0',
  `available_hit_dice` int NOT NULL DEFAULT '0',
  `age` int DEFAULT NULL,
  `height` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `weight` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `eyes` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `skin` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `hair` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `appearance` text COLLATE utf8mb4_unicode_ci,
  `allies_and_organizations` text COLLATE utf8mb4_unicode_ci,
  `additional_treasure` text COLLATE utf8mb4_unicode_ci,
  `character_history` text COLLATE utf8mb4_unicode_ci,
  `currenthp` int NOT NULL,
  `maxhp` int NOT NULL,
  `temporaryhp` int NOT NULL,
  `use_encumbrance` bit(1) NOT NULL,
  `subrace_id` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `class_id` (`class_id`),
  KEY `subclass_id` (`subclass_id`),
  KEY `background_id` (`background_id`),
  KEY `idx_character_name` (`name`),
  KEY `idx_character_level` (`level`),
  KEY `idx_character_user` (`user_id`),
  KEY `idx_char_race_class` (`race_id`,`class_id`),
  KEY `FKm16wqqlrylb007kb9l1a54f2v` (`subrace_id`),
  CONSTRAINT `characters_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
