/*!40000 ALTER TABLE `condition_descriptions` DISABLE KEYS */;
INSERT INTO `condition_descriptions` VALUES (1,'- A blinded creature can\'t see and automatically fails any ability check that requires sight.'),(1,'- Attack rolls against the creature have advantage, and the creature\'s attack rolls have disadvantage.'),(2,'- A charmed creature can\'t attack the charmer or target the charmer with harmful abilities or magical effects.'),(2,'- The charmer has advantage on any ability check to interact socially with the creature.'),(3,'- A deafened creature can\'t hear and automatically fails any ability check that requires hearing.'),(4,'Some special abilities and environmental hazards, such as starvation and the long-term effects of freezing or scorching temperatures, can lead to a special condition called exhaustion. Exhaustion is measured in six levels. An effect can give a creature one or more levels of exhaustion, as specified in the effect\'s description.'),(4,'1 - Disadvantage on ability checks'),(4,'2 - Speed halved'),(4,'3 - Disadvantage on attack rolls and saving throws'),(4,'4 - Hit point maximum halved'),(4,'5 - Speed reduced to 0'),(4,'6 - Death'),(4,'If an already exhausted creature suffers another effect that causes exhaustion, its current level of exhaustion increases by the amount specified in the effect\'s description.'),(4,'A creature suffers the effect of its current level of exhaustion as well as all lower levels. For example, a creature suffering level 2 exhaustion has its speed halved and has disadvantage on ability checks.'),(4,'An effect that removes exhaustion reduces its level as specified in the effect\'s description, with all exhaustion effects ending if a creature\'s exhaustion level is reduced below 1.'),(4,'Finishing a long rest reduces a creature\'s exhaustion level by 1, provided that the creature has also ingested some food and drink.'),(5,'- A frightened creature has disadvantage on ability checks and attack rolls while the source of its fear is within line of sight.'),(5,'- The creature can\'t willingly move closer to the source of its fear.'),(6,'- A grappled creature\'s speed becomes 0, and it can\'t benefit from any bonus to its speed.'),(6,'- The condition ends if the grappler is incapacitated (see the condition).'),(6,'- The condition also ends if an effect removes the grappled creature from the reach of the grappler or grappling effect, such as when a creature is hurled away by the thunderwave spell.'),(7,'- An incapacitated creature can\'t take actions or reactions.'),(8,'- An invisible creature is impossible to see without the aid of magic or a special sense. For the purpose of hiding, the creature is heavily obscured. The creature\'s location can be detected by any noise it makes or any tracks it leaves.'),(8,'- Attack rolls against the creature have disadvantage, and the creature\'s attack rolls have advantage.'),(9,'- A paralyzed creature is incapacitated (see the condition) and can\'t move or speak.'),(9,'- The creature automatically fails Strength and Dexterity saving throws.'),(9,'- Attack rolls against the creature have advantage.'),(9,'- Any attack that hits the creature is a critical hit if the attacker is within 5 feet of the creature.'),(10,'- A petrified creature is transformed, along with any nonmagical object it is wearing or carrying, into a solid inanimate substance (usually stone). Its weight increases by a factor of ten, and it ceases aging.'),(10,'- The creature is incapacitated (see the condition), can\'t move or speak, and is unaware of its surroundings.'),(10,'- Attack rolls against the creature have advantage.'),(10,'- The creature automatically fails Strength and Dexterity saving throws.'),(10,'- The creature has resistance to all damage.'),(10,'- The creature is immune to poison and disease, although a poison or disease already in its system is suspended, not neutralized.'),(11,'- A poisoned creature has disadvantage on attack rolls and ability checks.'),(12,'- A prone creature\'s only movement option is to crawl, unless it stands up and thereby ends the condition.'),(12,'- The creature has disadvantage on attack rolls.'),(12,'- An attack roll against the creature has advantage if the attacker is within 5 feet of the creature. Otherwise, the attack roll has disadvantage.'),(13,'- A restrained creature\'s speed becomes 0, and it can\'t benefit from any bonus to its speed.'),(13,'- Attack rolls against the creature have advantage, and the creature\'s attack rolls have disadvantage.'),(13,'- The creature has disadvantage on Dexterity saving throws.'),(14,'- A stunned creature is incapacitated (see the condition), can\'t move, and can speak only falteringly.'),(14,'- The creature automatically fails Strength and Dexterity saving throws.'),(14,'- Attack rolls against the creature have advantage.'),(15,'- An unconscious creature is incapacitated (see the condition), can\'t move or speak, and is unaware of its surroundings.'),(15,'- The creature drops whatever it\'s holding and falls prone.'),(15,'- The creature automatically fails Strength and Dexterity saving throws.'),(15,'- Attack rolls against the creature have advantage.'),(15,'- Any attack that hits the creature is a critical hit if the attacker is within 5 feet of the creature.');
/*!40000 ALTER TABLE `condition_descriptions` ENABLE KEYS */;
UNLOCK TABLES;

