INSERT INTO `damage_type_descriptions` VALUES (1,'The corrosive spray of a black dragon\'s breath and the dissolving enzymes secreted by a black pudding deal acid damage.'),(2,'Blunt force attacks, falling, constriction, and the like deal bludgeoning damage.'),(3,'The infernal chill radiating from an ice devil\'s spear and the frigid blast of a white dragon\'s breath deal cold damage.'),(4,'Red dragons breathe fire, and many spells conjure flames to deal fire damage.'),(5,'Force is pure magical energy focused into a damaging form. Most effects that deal force damage are spells, including magic missile and spiritual weapon.'),(6,'A lightning bolt spell and a blue dragon\'s breath deal lightning damage.'),(7,'Necrotic damage, dealt by certain undead and a spell such as chill touch, withers matter and even the soul.'),(8,'Puncturing and impaling attacks, including spears and monsters\' bites, deal piercing damage.'),(9,'Venomous stings and the toxic gas of a green dragon\'s breath deal poison damage.'),(10,'Mental abilities such as a psionic blast deal psychic damage.'),(11,'Radiant damage, dealt by a cleric\'s flame strike spell or an angel\'s smiting weapon, sears the flesh like fire and overloads the spirit with power.'),(12,'Swords, axes, and monsters\' claws deal slashing damage.'),(13,'A concussive burst of sound, such as the effect of the thunderwave spell, deals thunder damage.');
/*!40000 ALTER TABLE `damage_type_descriptions` ENABLE KEYS */;
UNLOCK TABLES;

