INSERT INTO `feats` VALUES (1,'actor','Actor','Skilled at mimicry and dramatics, you gain +1 Charisma, advantage on Deception/Performance when disguised, and can mimic voices or sounds you have heard.','None'),(2,'alert','Alert','Always on the lookout for danger: +5 bonus to initiative, can\'t be surprised while conscious, hidden creatures gain no advantage on attacks against you.','None'),(3,'athlete','Athlete','You have undergone extensive physical training: +1 Str or Dex, standing up uses only 5 ft of movement, climbing doesn\'t halve speed, you can make a running long/high jump after moving only 5 ft.','None'),(4,'charger','Charger','When you use your action to Dash, you can use a bonus action to make one melee attack or shove, adding +5 damage if you moved 10 ft in a straight line.','None'),(5,'crossbow-expert','Crossbow Expert','You ignore the loading property of crossbows, don\'t have disadvantage when firing in melee range, and can attack with a hand crossbow as a bonus action when you attack with a one-handed weapon.','None'),(6,'defensive-duelist','Defensive Duelist','When wielding a finesse weapon you are proficient with, you can use your reaction to add your proficiency bonus to AC against one melee attack that would hit you.','Dexterity 13'),(7,'dual-wielder','Dual Wielder','You master fighting with two weapons: +1 AC while wielding two melee weapons, can use two-weapon fighting with non-light weapons, and can draw or stow two weapons at once.','None'),(8,'dungeon-delver','Dungeon Delver','Alert to the perils of dungeons: advantage on Perception and Investigation to detect secret doors, advantage on saves vs. traps, resistance to trap damage, can search for traps at normal pace.','None'),(9,'durable','Durable','Hardy and resilient: +1 Constitution, when you roll Hit Dice to regain hp, the minimum hp regained equals twice your Constitution modifier (minimum 2).','None'),(10,'elemental-adept','Elemental Adept','Choose acid, cold, fire, lightning, or thunder. Spells you cast ignore resistance to that damage type, and when you roll damage for such a spell, treat any 1 on a die as a 2.','Spellcasting ability'),(11,'grappler','Grappler','You\'ve developed the skills necessary to hold your own in close-quarters grappling: advantage on attack rolls against a creature you are grappling, and you can use your action to try to pin it (restrained).','Strength 13'),(12,'great-weapon-master','Great-Weapon Master','When you score a critical hit or reduce a creature to 0 hp with a heavy melee weapon, you can make one melee weapon attack as a bonus action. You can also choose -5 to hit for +10 damage.','None'),(13,'healer','Healer','You are an able physician: using a healer\'s kit stabilises a creature without a check; using the kit as an action restores 1d6+4 hp plus HD, once per creature per short rest.','None'),(14,'heavily-armored','Heavily Armored','+1 Strength and proficiency with heavy armor.','Proficiency with medium armor'),(15,'heavy-armor-master','Heavy Armor Master','+1 Strength; while wearing heavy armor, bludgeoning, piercing, and slashing damage from non-magical attacks is reduced by 3.','Proficiency with heavy armor'),(16,'inspiring-leader','Inspiring Leader','After a 10-minute speech, up to 6 allies who can hear you gain temporary hp equal to your level + Charisma modifier.','Charisma 13'),(17,'keen-mind','Keen Mind','+1 Intelligence; you always know north, the number of hours until sunrise/sunset, and can recall anything you saw or heard in the past month.','None'),(18,'lightly-armored','Lightly Armored','+1 Strength or Dexterity and proficiency with light armor.','None'),(19,'linguist','Linguist','+1 Intelligence, learn 3 languages of your choice, and you can create written ciphers only you or those you teach can decipher.','None'),(20,'lucky','Lucky','You have inexplicable luck. You have 3 luck points per long rest. Spend one to roll an extra d20 on an attack, ability check, or save (choose which d20 to use), or force an attacker to reroll their attack.','None'),(21,'mage-slayer','Mage Slayer','When a creature within 5 ft casts a spell, you can use your reaction to make a melee attack against it; you cause disadvantage on its Concentration save, and you have advantage on saves against spells cast by creatures within 5 ft.','None'),(22,'magic-initiate','Magic Initiate','Choose a class: bard, cleric, druid, sorcerer, warlock, or wizard. Learn 2 cantrips and one 1st-level spell from that class\'s list; you can cast the spell once per long rest without a slot.','None'),(23,'martial-adept','Martial Adept','You learn two maneuvers from the Battle Master archetype and gain one superiority die (d6) to fuel them, regained on a short or long rest.','None'),(24,'medium-armor-master','Medium Armor Master','No disadvantage on Stealth while wearing medium armor, and max Dexterity bonus while wearing it becomes +3 instead of +2.','Proficiency with medium armor'),(25,'mobile','Mobile','Speed increases by 10 ft; when you use Dash, difficult terrain doesn\'t cost extra movement; when you make a melee attack you don\'t provoke opportunity attacks from that creature.','None'),(26,'moderately-armored','Moderately Armored','+1 Strength or Dexterity and proficiency with medium armor and shields.','Proficiency with light armor'),(27,'mounted-combatant','Mounted Combatant','Advantage on melee attacks against unmounted creatures smaller than your mount; can redirect attacks aimed at mount to yourself; mount doesn\'t take damage on a successful Dex save (half on fail).','None'),(28,'observant','Observant','+1 Intelligence or Wisdom; can read lips; +5 bonus to passive Perception and passive Investigation.','None'),(29,'polearm-master','Polearm Master','When you attack with a glaive, halberd, pike, or quarterstaff, you can use a bonus action to attack with the butt end (1d4 bludgeoning). You also get an opportunity attack when a creature enters your reach.','None'),(30,'resilient','Resilient','Choose one ability score: +1 to that score and you gain proficiency in saving throws using it.','None'),(31,'ritual-caster','Ritual Caster','Choose a class: bard, cleric, druid, sorcerer, warlock, or wizard. You learn two 1st-level ritual spells from that class and can cast them as rituals; you can add more ritual spells found as scrolls or books.','Intelligence or Wisdom 13'),(32,'savage-attacker','Savage Attacker','Once per turn, when you roll weapon attack damage, you can reroll the damage dice and use either total.','None'),(33,'sentinel','Sentinel','When you hit a creature with an opportunity attack its speed drops to 0. Creatures within 5 ft provoke opportunity attacks even after Disengage. When a creature attacks someone other than you within 5 ft, you can make a reaction melee attack.','None'),(34,'sharpshooter','Sharpshooter','Ignore long-range penalty and three-quarters and half cover; optionally take -5 to hit for +10 damage on ranged attacks.','None'),(35,'shield-master','Shield Master','If you take the Attack action, add shield bash as a bonus action (1d4 + Str). Add shield\'s AC bonus to Dex saves against spells that target only you. Use reaction to take no damage on a successful Dex save instead of half.','None'),(36,'skilled','Skilled','Gain proficiency in any combination of three skills or tools of your choice.','None'),(37,'skulker','Skulker','Can try to hide when lightly obscured; missing an attack while hiding doesn\'t reveal you; dim light doesn\'t impose disadvantage on Perception checks.','Dexterity 13'),(38,'spell-sniper','Spell Sniper','Choose a spellcasting class. Learn a cantrip from it that requires an attack roll. Double the range of ranged spell attacks; ranged spell attacks ignore half and three-quarters cover.','Spellcasting ability'),(39,'tavern-brawler','Tavern Brawler','+1 Strength or Constitution; proficient with improvised weapons; unarmed strikes deal 1d4 bludgeoning; can attempt to grapple as a bonus action after hitting with an unarmed strike or improvised weapon.','None'),(40,'tough','Tough','HP maximum increases by 2 per level (including retroactively for levels already gained).','None'),(41,'war-caster','War Caster','Advantage on Concentration saves; can perform somatic components with weapons/shield in hand; when a creature provokes an opportunity attack from you, you can cast a spell targeting it instead.','Spellcasting ability'),(42,'weapon-master','Weapon Master','+1 Strength or Dexterity and proficiency with four weapons of your choice.','None');
/*!40000 ALTER TABLE `feats` ENABLE KEYS */;
UNLOCK TABLES;

