LOCK TABLES `racial_traits` WRITE;
/*!40000 ALTER TABLE `racial_traits` DISABLE KEYS */;
INSERT INTO `racial_traits` VALUES (1,'You have draconic ancestry. Choose one type of dragon from the Draconic Ancestry table. Your breath weapon and damage resistance are determined by the dragon type, as shown in the table.','draconic-ancestry','Draconic Ancestry','CHOICE_REQUIRED'),(2,'You can use your action to exhale destructive energy. Your draconic ancestry determines the size, shape, and damage type of the exhalation.\nWhen you use your breath weapon, each creature in the area of the exhalation must make a saving throw, the type of which is determined by your draconic ancestry. The DC for this saving throw equals 8 + your Constitution modifier + your proficiency bonus. A creature takes 2d6 damage on a failed save, and half as much damage on a successful one. The damage increases to 3d6 at 6th level, 4d6 at 11th level, and 5d6 at 16th level.\nAfter you use your breath weapon, you cannot use it again until you complete a short or long rest.','breath-weapon','Breath Weapon','CHOICE_REQUIRED'),(3,'You have resistance to the damage type associated with your draconic ancestry.','damage-resistance','Damage Resistance','PASSIVE'),(4,'You have superior vision in dark and dim conditions. You can see in dim light within 60 feet of you as if it were bright light, and in darkness as if it were dim light. You cannot discern color in darkness, only shades of gray.','darkvision','Darkvision','PASSIVE'),(5,'You have advantage on saving throws against poison, and you have resistance against poison damage.','dwarven-resilience','Dwarven Resilience','COMBAT'),(6,'Whenever you make an Intelligence (History) check related to the origin of stonework, you are considered proficient in the History skill and add double your proficiency bonus to the check, instead of your normal proficiency bonus.','stonecunning','Stonecunning','PASSIVE'),(7,'You have proficiency with the battleaxe, handaxe, light hammer, and warhammer.','dwarven-combat-training','Dwarven Combat Training','COMBAT'),(8,'You gain proficiency with the artisan\'s tools of your choice: smith\'s tools, brewer\'s supplies, or mason\'s tools.','tool-proficiency','Tool Proficiency','CHOICE_REQUIRED'),(9,'You have advantage on saving throws against being charmed, and magic cannot put you to sleep.','fey-ancestry','Fey Ancestry','PASSIVE'),(10,'Elves do not need to sleep. Instead, they meditate deeply, remaining semiconscious, for 4 hours a day. (The Common word for such meditation is \"trance.\") While meditating, you can dream after a fashion; such dreams are actually mental exercises that have become reflexive through years of practice. After resting this way, you gain the same benefit that a human does from 8 hours of sleep.','trance','Trance','COMBAT'),(11,'You have proficiency in the Perception skill.','keen-senses','Keen Senses','PASSIVE'),(12,'You have advantage on all Intelligence, Wisdom, and Charisma saving throws against magic.','gnome-cunning','Gnome Cunning','COMBAT'),(13,'You gain proficiency in two skills of your choice.','skill-versatility','Skill Versatility','CHOICE_REQUIRED'),(14,'When you score a critical hit with a melee weapon attack, you can roll one of the weapon\'s damage dice one additional time and add it to the extra damage of the critical hit.','savage-attacks','Savage Attacks','COMBAT'),(15,'When you are reduced to 0 hit points but not killed outright, you can drop to 1 hit point instead. you cannot use this feature again until you finish a long rest.','relentless-endurance','Relentless Endurance','COMBAT'),(16,'You gain proficiency in the Intimidation skill.','menacing','Menacing','PASSIVE'),(17,'You have advantage on saving throw against being frightened.','brave','Brave','COMBAT'),(18,'You can move through the space of any creature that is of a size larger than yours.','halfling-nimbleness','Halfling Nimbleness','COMBAT'),(19,'When you roll a 1 on the d20 for an attack roll, ability check, or saving throw, you can reroll the die and must use the new roll.','lucky','Lucky','COMBAT'),(20,'You have resistance to fire damage.','hellish-resistance','Hellish Resistance','PASSIVE'),(21,'You know the thaumaturgy cantrip. When you reach 3rd level, you can cast the hellish rebuke spell as a 2nd-level spell once with this trait and regain the ability to do so when you finish a long rest. When you reach 5th level, you can cast the darkness spell once with this trait and regain the ability to do so when you finish a long rest. Charisma is your spellcasting ability for these spells.','infernal-legacy','Infernal Legacy','PASSIVE'),(22,'You have proficiency with the longsword, shortsword, shortbow, and longbow.','elf-weapon-training','Elf Weapon Training','PASSIVE'),(23,'You know one cantrip of your choice form the wizard spell list. Intelligence is your spellcasting ability for it.','high-elf-cantrip','High Elf Cantrip','PASSIVE'),(24,'You can speak, read, and write one extra language of your choice.','extra-language','Extra Language','CHOICE_REQUIRED'),(25,'Your hit point maximum increases by 1, and it increases by 1 every time you gain a level.','dwarven-toughness','Dwarven Toughness','PASSIVE'),(26,'You can attempt to hide even when you are obscured only by a creature that is at least one size larger than you.','naturally-stealthy','Naturally Stealthy','PASSIVE'),(27,'Whenever you make an Intelligence (History) check related to magic items, alchemical objects, or technological devices, you can add twice your proficiency bonus, instead of any proficiency bonus you normally apply.','artificers-lore','Artificer\'s Lore','COMBAT'),(28,'You have proficiency with artisan\'s tools (tinker\'s tools). Using those tools, you can spend 1 hour and 10 gp worth of materials to construct a Tiny clockwork device (AC 5, 1 hp). The device ceases to function after 24 hours (unless you spend 1 hour repairing it to keep the device functioning), or when you use your action to dismantle it; at that time, you can reclaim the materials used to create it. You can have up to three such devices active at a time.\nWhen you create a device, choose one of the following options:\nClockwork Toy: This toy is a clockwork animal, monster, or person, such as a frog, mouse, bird, dragon, or soldier. When placed on the ground, the toy moves 5 feet across the ground on each of your turns in a random direction. It makes noises as appropriate to the creature it represents.\nFire Starter: The device produces a miniature flame, which you can use to light a candle, torch, or campfire. Using the device requires your action.\nMusic Box: When opened, this music box plays a single song at a moderate volume. The box stops playing when it reaches the song\'s end or when it is closed.','tinker','Tinker','COMBAT'),(29,NULL,'dwarven-armor-training','Dwarven Armor Training',NULL),(30,NULL,'fleet-of-foot','Fleet of Foot',NULL),(31,NULL,'mask-of-the-wild','Mask of the Wild',NULL),(32,NULL,'superior-darkvision','Superior Darkvision',NULL),(33,NULL,'sunlight-sensitivity','Sunlight Sensitivity',NULL),(34,NULL,'drow-magic','Drow Magic',NULL),(35,NULL,'drow-weapon-training','Drow Weapon Training',NULL),(36,NULL,'stout-resilience','Stout Resilience',NULL),(37,NULL,'natural-illusionist','Natural Illusionist',NULL),(38,NULL,'speak-with-small-beasts','Speak with Small Beasts',NULL);
/*!40000 ALTER TABLE `racial_traits` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `skills`
--

DROP TABLE IF EXISTS `skills`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `skills` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `index_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `ability_score` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`id`),
  UNIQUE KEY `index_name` (`index_name`),
  KEY `idx_skills_name` (`name`)
) ENGINE=InnoDB AUTO_INCREMENT=19 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `skills`
--

LOCK TABLES `skills` WRITE;
/*!40000 ALTER TABLE `skills` DISABLE KEYS */;
INSERT INTO `skills` VALUES (1,'acrobatics','Acrobatics','dex','Your Dexterity (Acrobatics) check covers your attempt to stay on your feet in a tricky situation, such as when you\'re trying to run across a sheet of ice, balance on a tightrope, or stay upright on a rocking ship\'s deck. The GM might also call for a Dexterity (Acrobatics) check to see if you can perform acrobatic stunts, including dives, rolls, somersaults, and flips.'),(2,'animal-handling','Animal Handling','wis','When there is any question whether you can calm down a domesticated animal, keep a mount from getting spooked, or intuit an animal\'s intentions, the GM might call for a Wisdom (Animal Handling) check. You also make a Wisdom (Animal Handling) check to control your mount when you attempt a risky maneuver.'),(3,'arcana','Arcana','int','Your Intelligence (Arcana) check measures your ability to recall lore about spells, magic items, eldritch symbols, magical traditions, the planes of existence, and the inhabitants of those planes.'),(4,'athletics','Athletics','str','Your Strength (Athletics) check covers difficult situations you encounter while climbing, jumping, or swimming.'),(5,'deception','Deception','cha','Your Charisma (Deception) check determines whether you can convincingly hide the truth, either verbally or through your actions. This deception can encompass everything from misleading others through ambiguity to telling outright lies. Typical situations include trying to fast- talk a guard, con a merchant, earn money through gambling, pass yourself off in a disguise, dull someone\'s suspicions with false assurances, or maintain a straight face while telling a blatant lie.'),(6,'history','History','int','Your Intelligence (History) check measures your ability to recall lore about historical events, legendary people, ancient kingdoms, past disputes, recent wars, and lost civilizations.'),(7,'insight','Insight','wis','Your Wisdom (Insight) check decides whether you can determine the true intentions of a creature, such as when searching out a lie or predicting someone\'s next move. Doing so involves gleaning clues from body language, speech habits, and changes in mannerisms.'),(8,'intimidation','Intimidation','cha','When you attempt to influence someone through overt threats, hostile actions, and physical violence, the GM might ask you to make a Charisma (Intimidation) check. Examples include trying to pry information out of a prisoner, convincing street thugs to back down from a confrontation, or using the edge of a broken bottle to convince a sneering vizier to reconsider a decision.'),(9,'investigation','Investigation','int','When you look around for clues and make deductions based on those clues, you make an Intelligence (Investigation) check. You might deduce the location of a hidden object, discern from the appearance of a wound what kind of weapon dealt it, or determine the weakest point in a tunnel that could cause it to collapse. Poring through ancient scrolls in search of a hidden fragment of knowledge might also call for an Intelligence (Investigation) check.'),(10,'medicine','Medicine','wis','A Wisdom (Medicine) check lets you try to stabilize a dying companion or diagnose an illness.'),(11,'nature','Nature','int','Your Intelligence (Nature) check measures your ability to recall lore about terrain, plants and animals, the weather, and natural cycles.'),(12,'perception','Perception','wis','Your Wisdom (Perception) check lets you spot, hear, or otherwise detect the presence of something. It measures your general awareness of your surroundings and the keenness of your senses. For example, you might try to hear a conversation through a closed door, eavesdrop under an open window, or hear monsters moving stealthily in the forest. Or you might try to spot things that are obscured or easy to miss, whether they are orcs lying in ambush on a road, thugs hiding in the shadows of an alley, or candlelight under a closed secret door.'),(13,'performance','Performance','cha','Your Charisma (Performance) check determines how well you can delight an audience with music, dance, acting, storytelling, or some other form of entertainment.'),(14,'persuasion','Persuasion','cha','When you attempt to influence someone or a group of people with tact, social graces, or good nature, the GM might ask you to make a Charisma (Persuasion) check. Typically, you use persuasion when acting in good faith, to foster friendships, make cordial requests, or exhibit proper etiquette. Examples of persuading others include convincing a chamberlain to let your party see the king, negotiating peace between warring tribes, or inspiring a crowd of townsfolk.'),(15,'religion','Religion','int','Your Intelligence (Religion) check measures your ability to recall lore about deities, rites and prayers, religious hierarchies, holy symbols, and the practices of secret cults.'),(16,'sleight-of-hand','Sleight of Hand','dex','Whenever you attempt an act of legerdemain or manual trickery, such as planting something on someone else or concealing an object on your person, make a Dexterity (Sleight of Hand) check. The GM might also call for a Dexterity (Sleight of Hand) check to determine whether you can lift a coin purse off another person or slip something out of another person\'s pocket.'),(17,'stealth','Stealth','dex','Make a Dexterity (Stealth) check when you attempt to conceal yourself from enemies, slink past guards, slip away without being noticed, or sneak up on someone without being seen or heard.'),(18,'survival','Survival','wis','The GM might ask you to make a Wisdom (Survival) check to follow tracks, hunt wild game, guide your group through frozen wastelands, identify signs that owlbears live nearby, predict the weather, or avoid quicksand and other natural hazards.');
/*!40000 ALTER TABLE `skills` ENABLE KEYS */;
UNLOCK TABLES;

